// Normalize both entry points (form + webhook) into one canonical client record.
const src = $json.body ? $json.body : $json;

const pick = (...keys) => {
  for (const k of keys) {
    const v = src[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};

const clientName = pick('Client Name', 'client_name', 'name');
const clientEmail = pick('Client Email', 'client_email', 'email').toLowerCase();
const company = pick('Company', 'company');
const projectName = pick('Project Name', 'project_name', 'project');
const projectType = pick('Project Type', 'project_type');
const feeRaw = pick('Project Fee (USD)', 'fee', 'amount');
const depositRaw = pick('Deposit Required', 'deposit_percent', 'deposit');
const startDate = pick('Target Start Date', 'start_date');
const notes = pick('Notes for the file', 'notes');

const fee = parseFloat(String(feeRaw).replace(/[^0-9.]/g, '')) || 0;
const depositPercent = parseInt(String(depositRaw).replace(/[^0-9]/g, ''), 10) || 50;
const depositAmount = Math.round((fee * depositPercent / 100) * 100) / 100;

const validEmail = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(clientEmail);

return {
  json: {
    clientName,
    clientEmail,
    company,
    projectName,
    projectType,
    fee,
    depositPercent,
    depositAmount,
    startDate,
    notes,
    validEmail,
    status: 'onboarding-started',
    source: $json.body ? 'webhook' : 'n8n-form',
    onboardedAt: new Date().toISOString()
  }
};

